// ──────────────────────────────────────────────────────────────────
// Node: Set Configuration
// Purpose: Central place for all brand / path settings.
// ──────────────────────────────────────────────────────────────────
const config = {
  subject:        'Economic and Social Issues',
  chapter:        'Economic Growth and Development',
  phone:          '+91 9999466225',
  website:        'www.anujjindal.in',
  blueColour:     '#1B71AC',
  greenColour:    '#2AB573',
  headerLogoUrl:  'https://anujjindal.in/wp-content/uploads/2022/05/LOGO-FULL-01.png',
  watermarkUrl:   'https://anujjindal.in/wp-content/uploads/2023/02/LOGO-CROP.png',
  // Absolute path to the folder that contains generate_pdf.py AND the PNG images
  workDir:        '/data/workflows/economic-notes',
  outputFilename: 'Economic_Growth_and_Development.pdf',
};

return [{ json: config }];

// ──────────────────────────────────────────────────────────────────
// Node: Prepare Python Command
// Assembles the shell command that will invoke generate_pdf.py
// ──────────────────────────────────────────────────────────────────
const cfg   = $('Set Configuration').item.json;
const outPath = `${cfg.workDir}/${cfg.outputFilename}`;

const cmd = [
  'python3',
  `"${cfg.workDir}/generate_pdf.py"`,
  `--output "${outPath}"`,
  `--img-dir "${cfg.workDir}"`,
].join(' ');

return [{ json: { ...cfg, cmd, outPath } }];

// ──────────────────────────────────────────────────────────────────
// Node: Check Result
// Validates the shell command succeeded and formats a status report.
// ──────────────────────────────────────────────────────────────────
const exitCode = $input.item.json.exitCode;
const stdout   = $input.item.json.stdout || '';
const stderr   = $input.item.json.stderr || '';
const cfg      = $('Prepare Python Command').item.json;

if (exitCode !== 0) {
  throw new Error(`PDF generation failed (exit ${exitCode}):\n${stderr}`);
}

return [{
  json: {
    success:    true,
    outputPath: cfg.outPath,
    message:    stdout.trim(),
    subject:    cfg.subject,
    chapter:    cfg.chapter,
    timestamp:  new Date().toISOString(),
  }
}];

// ──────────────────────────────────────────────────────────────────
// Node: Success Summary
// Emits a clean summary JSON for downstream nodes / webhooks.
// ──────────────────────────────────────────────────────────────────
const d = $input.item.json;
return [{
  json: {
    status:     'SUCCESS',
    pdf:        d.outputPath,
    subject:    d.subject,
    chapter:    d.chapter,
    generatedAt: d.timestamp,
    note:       'PDF ready for download / email / upload.',
  }
}];

// ──────────────────────────────────────────────────────────────────
// Node: Error Handler
// Formats the error into a structured response.
// ──────────────────────────────────────────────────────────────────
const errMsg = $input.item.json.error?.message
               || 'Unknown error in PDF generation';
return [{
  json: {
    status:    'FAILED',
    error:     errMsg,
    timestamp: new Date().toISOString(),
  }
}];
